'use client';

import { useState } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { toast } from '@/hooks/use-toast';
import { Save, Settings, Bell, Shield, Database } from 'lucide-react';

export default function AdminSettingsPage() {
    const [maintenanceMode, setMaintenanceMode] = useState(false);
    const [emailNotifications, setEmailNotifications] = useState(true);
    const [debugMode, setDebugMode] = useState(false);

    const handleSave = () => {
        toast({ title: 'Configurações salvas', description: 'As alterações foram aplicadas' });
    };

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-2xl font-bold">Configurações do Sistema</h1>
                <p className="text-muted-foreground">Gerencie as configurações globais da plataforma</p>
            </div>

            <div className="grid gap-6 md:grid-cols-2">
                {/* General Settings */}
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Settings className="h-5 w-5" />
                            Configurações Gerais
                        </CardTitle>
                        <CardDescription>Configurações básicas do sistema</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="flex items-center justify-between">
                            <div className="space-y-0.5">
                                <Label>Modo de Manutenção</Label>
                                <p className="text-sm text-muted-foreground">
                                    Desabilita acesso ao sistema
                                </p>
                            </div>
                            <Switch
                                checked={maintenanceMode}
                                onCheckedChange={setMaintenanceMode}
                            />
                        </div>

                        <div className="flex items-center justify-between">
                            <div className="space-y-0.5">
                                <Label>Modo Debug</Label>
                                <p className="text-sm text-muted-foreground">
                                    Ativa logs detalhados
                                </p>
                            </div>
                            <Switch
                                checked={debugMode}
                                onCheckedChange={setDebugMode}
                            />
                        </div>
                    </CardContent>
                </Card>

                {/* Notification Settings */}
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Bell className="h-5 w-5" />
                            Notificações
                        </CardTitle>
                        <CardDescription>Configure alertas e notificações</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="flex items-center justify-between">
                            <div className="space-y-0.5">
                                <Label>Notificações por Email</Label>
                                <p className="text-sm text-muted-foreground">
                                    Receba alertas por email
                                </p>
                            </div>
                            <Switch
                                checked={emailNotifications}
                                onCheckedChange={setEmailNotifications}
                            />
                        </div>
                    </CardContent>
                </Card>

                {/* Security Settings */}
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Shield className="h-5 w-5" />
                            Segurança
                        </CardTitle>
                        <CardDescription>Configurações de segurança do sistema</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="space-y-2">
                            <Label>Tempo de Sessão (minutos)</Label>
                            <Input type="number" defaultValue={60} />
                        </div>
                        <div className="space-y-2">
                            <Label>Máximo de Tentativas de Login</Label>
                            <Input type="number" defaultValue={5} />
                        </div>
                    </CardContent>
                </Card>

                {/* Database Settings */}
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Database className="h-5 w-5" />
                            Database
                        </CardTitle>
                        <CardDescription>Configurações de banco de dados</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="space-y-2">
                            <Label>URL do Supabase</Label>
                            <Input disabled value={process.env.NEXT_PUBLIC_SUPABASE_URL || 'Não configurado'} />
                        </div>
                        <p className="text-xs text-muted-foreground">
                            Configurações sensíveis são gerenciadas via variáveis de ambiente
                        </p>
                    </CardContent>
                </Card>
            </div>

            <div className="flex justify-end">
                <Button onClick={handleSave}>
                    <Save className="h-4 w-4 mr-2" />
                    Salvar Configurações
                </Button>
            </div>
        </div>
    );
}
